import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [messages, setMessages] = useState([]);
  const [tab, setTab] = useState('users');
  const [search, setSearch] = useState('');

  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data || []));
    API.get('/admin/posts').then(res => setPosts(res.data || []));
    API.get('/admin/comments').then(res => setComments(res.data || []));
    API.get('/admin/messages').then(res => setMessages(res.data || []));
  }, []);

  // ================= HELPERS =================
  const getMessageStatus = (m) =>
    (m.status === 'read' || m.read || m.isRead) ? 'READ' : 'NEW';

  const isMessageRead = (m) =>
    (m.status === 'read' || m.read || m.isRead);

  // ================= FILTER =================
  const filteredData = () => {
    const keyword = search.toLowerCase();

    const map = {
      users: users.filter(u =>
        u.name?.toLowerCase().includes(keyword) ||
        u.email?.toLowerCase().includes(keyword)
      ),
      posts: posts.filter(p =>
        p.title?.toLowerCase().includes(keyword) ||
        p.author?.name?.toLowerCase().includes(keyword)
      ),
      comments: comments.filter(c =>
        c.body?.toLowerCase().includes(keyword) ||
        c.author?.name?.toLowerCase().includes(keyword)
      ),
      messages: messages.filter(m =>
        m.name?.toLowerCase().includes(keyword) ||
        m.email?.toLowerCase().includes(keyword) ||
        (m.body || m.message || '').toLowerCase().includes(keyword)
      )
    };

    return map[tab];
  };

  // ================= ACTIONS =================
  const markAsRead = async (id) => {
    await API.put(`/admin/messages/${id}/read`);
    setMessages(prev =>
      prev.map(m =>
        m._id === id ? { ...m, status: 'read', read: true } : m
      )
    );
  };

  const deleteMessage = async (id) => {
    await API.delete(`/admin/messages/${id}`);
    setMessages(prev => prev.filter(m => m._id !== id));
  };

  // ================= STYLES =================
  const styles = {
    page: {
      background: '#f6f7fb',
      minHeight: '100vh',
      padding: '40px'
    },
    container: {
      maxWidth: '1100px',
      margin: 'auto',
      background: '#fff',
      padding: '30px',
      borderRadius: '20px',
      boxShadow: '0 10px 30px rgba(0,0,0,0.08)'
    },
    header: {
      fontSize: '28px',
      fontWeight: '700',
      marginBottom: '20px'
    },
    tabs: {
      display: 'flex',
      gap: '10px',
      marginBottom: '20px'
    },
    tab: {
      padding: '10px 20px',
      borderRadius: '20px',
      border: 'none',
      cursor: 'pointer',
      background: '#eee'
    },
    activeTab: {
      background: '#0c4b34',
      color: '#fff'
    },
    search: {
      width: '100%',
      padding: '12px',
      borderRadius: '12px',
      border: '1px solid #ddd',
      marginBottom: '20px'
    },
    tableWrapper: {
      maxHeight: '400px',
      overflowY: 'auto',
      borderRadius: '10px',
      border: '1px solid #eee'
    },
    table: {
      width: '100%',
      borderCollapse: 'collapse'
    },
    th: {
      position: 'sticky',
      top: 0,
      background: '#0c4b34',
      color: '#fff',
      padding: '12px'
    },
    td: {
      padding: '12px',
      borderBottom: '1px solid #eee'
    },
    btn: {
      padding: '6px 12px',
      borderRadius: '8px',
      border: 'none',
      cursor: 'pointer',
      marginRight: '5px'
    },
    badge: (status) => ({
      padding: '5px 10px',
      borderRadius: '10px',
      fontSize: '12px',
      color: '#fff',
      background: status === 'READ' ? 'green' : 'orange'
    })
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <div style={styles.header}>Admin Dashboard</div>

        {/* TABS */}
        <div style={styles.tabs}>
          {['users', 'posts', 'comments', 'messages'].map(t => (
            <button
              key={t}
              onClick={() => setTab(t)}
              style={{
                ...styles.tab,
                ...(tab === t ? styles.activeTab : {})
              }}
            >
              {t.toUpperCase()}
            </button>
          ))}
        </div>

        {/* SEARCH */}
        <input
          style={styles.search}
          placeholder={`Search ${tab}...`}
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        {/* TABLE */}
        <div style={styles.tableWrapper}>
          <table style={styles.table}>
            <thead>
              {tab === 'messages' && (
                <tr>
                  <th style={styles.th}>Name</th>
                  <th style={styles.th}>Email</th>
                  <th style={styles.th}>Message</th>
                  <th style={styles.th}>Status</th>
                  <th style={styles.th}>Action</th>
                </tr>
              )}
            </thead>

            <tbody>
              {tab === 'messages' &&
                filteredData().map(m => {
                  const status = getMessageStatus(m);

                  return (
                    <tr key={m._id}>
                      <td style={styles.td}>{m.name}</td>
                      <td style={styles.td}>{m.email}</td>
                      <td style={styles.td}>{m.body || m.message}</td>
                      <td style={styles.td}>
                        <span style={styles.badge(status)}>
                          {status}
                        </span>
                      </td>
                      <td style={styles.td}>
                        {!isMessageRead(m) && (
                          <button
                            style={{ ...styles.btn, background: 'green', color: '#fff' }}
                            onClick={() => markAsRead(m._id)}
                          >
                            Mark Read
                          </button>
                        )}
                        <button
                          style={{ ...styles.btn, background: 'red', color: '#fff' }}
                          onClick={() => deleteMessage(m._id)}
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  );
                })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminPage;
